import React, { useEffect, useState } from 'react';
import axios from 'axios';

function FarmListPage() {
  const [farms, setFarms] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:10000/api/farms')
      .then(res => setFarms(res.data))
      .catch(err => console.error('❌ Lỗi lấy danh sách:', err));
  }, []);

  return (
    <div style={{ padding: 20 }}>
      <h2>📋 Danh sách cơ sở nuôi</h2>
      <table border="1" cellPadding="8">
        <thead>
          <tr>
            <th>Tên cơ sở</th>
            <th>Tỉnh</th>
            <th>Huyện</th>
            <th>Xã</th>
            <th>Chủ trại</th>
            <th>Số điện thoại</th>
          </tr>
        </thead>
        <tbody>
          {farms.map((f, i) => (
            <tr key={i}>
              <td>{f.tenCoSo}</td>
              <td>{f.tinh}</td>
              <td>{f.huyen}</td>
              <td>{f.xa}</td>
              <td>{f.chuTrai}</td>
              <td>{f.soDienThoai}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default FarmListPage;
